#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define BS 16

__kernel void lud_diagonal(__global float* a, __local float* shared_mem, int size, int offset)
{
    int i = get_global_id(0);
    if (i >= BS) return;

    // Macros from original code adapted
    #define AA(_i,_j) a[offset*size + _i*size + _j + offset]

    // Diagonal block LU factorization
    for (int j = i; j < BS; j++) {
        for (int k = 0; k < i; k++) {
            AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
        }
    }

    float temp = 1.f / AA(i,i);
    for (int j = i + 1; j < BS; j++) {
        for (int k = 0; k < i; k++) {
            AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
        }
        AA(j,i) = AA(j,i) * temp;
    }
}

__kernel void lud_perimeter(__global float* a, __local float* temp_lud, __local float* temp_a, __local float* temp_b, int size, int offset)
{
    int gid = get_global_id(0);

    int chunks_in_inter_row = (size - offset - BS) / BS;
    if (gid >= chunks_in_inter_row) return;

    int i, j, k;
    int i_global = offset;
    int j_global = offset + BS * (gid + 1);

    // Load diagonal block to temp_lud
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_lud[i * BS + j] = a[size * (i + offset) + offset + j];
        }
    }

    // Update top perimeter block row
    for (j = 0; j < BS; j++) {
        for (i = 0; i < BS; i++) {
            float sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp_lud[i * BS + k] * a[(i_global + k) * size + (j_global + j)];
            }
            a[(i_global + i) * size + (j_global + j)] = a[(i_global + i) * size + (j_global + j)] - sum;
        }
    }

    // Update left perimeter block column
    j_global = offset;
    i_global = offset + BS * (gid + 1);

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            float sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += a[(i_global + i) * size + (j_global + k)] * temp_lud[k * BS + j];
            }
            a[(i_global + i) * size + (j_global + j)] = (a[(i_global + i) * size + (j_global + j)] - sum) / a[(offset + j) * size + offset + j];
        }
    }
}

__kernel void lud_internal(__global float* a, __local float* temp_top, __local float* temp_left, int size, int offset)
{
    int gx = get_global_id(0);
    int gy = get_global_id(1);

    int chunks_in_inter_row = (size - offset - BS) / BS;

    if (gx >= chunks_in_inter_row || gy >= chunks_in_inter_row) return;

    int chunk_idx = gy * chunks_in_inter_row + gx;

    int i_global = offset + BS * (1 + gy);
    int j_global = offset + BS * (1 + gx);

    int i, j, k;

    // Load top block into temp_top
    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++) {
            temp_top[i * BS + j] = a[(offset + i) * size + j + j_global];
            temp_left[i * BS + j] = a[(i + i_global) * size + offset + j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float sum[BS];
    for (j = 0; j < BS; j++) sum[j] = 0.f;

    for (i = 0; i < BS; i++) {
        for (k = 0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[i * BS + k] * temp_top[k * BS + j];
            }
        }
        for (j = 0; j < BS; j++) {
            a[(i + i_global) * size + j + j_global] -= sum[j];
            sum[j] = 0.f;
        }
    }
}
